import Typed from "react-typed";
import { Quotes } from "../data/Quotes";
import { useEffect, useState } from "react";
const About = () => {
  const [quotes, setQuotes] = useState([]);
  useEffect(() => {
    let index = Math.round(Math.random() * Quotes.length);
    setQuotes([Quotes[index]]);
  }, []);
  console.log(quotes);
  return (
    <div className="w-full mt-1 flex flex-col justify-center items-center font-fontText dark:text-white text-slate-800">
      <Typed
        className="text-xl text-center font-fontHead"
        strings={["Muhammad Fauzi Nur Aziz"]}
        loop
        typeSpeed={100}
        backSpeed={70}
        data-aos="zoom-in"
        data-aos-duration="2000"
        data-aos-once="true"
      />
      <h3
        className="text-slate-900 dark:text-white text-md font-semibold"
        data-aos="zoom-in"
        data-aos-duration="2000"
        data-aos-once="true"
      >
        Mahasiswa |{" "}
        <span className="text-red-600 dark:text-red-500">Pengangguran</span>
      </h3>
      {quotes.map((item) => {
        return (
          <div
            className="text-center mt-5 py-5 border-t-8 border-b-8 border-double border-[#a71580] dark:border-[#c22e9a] rounded-2xl text-black dark:text-white text-sm w-full"
            data-aos="fade-up"
            data-aos-duration="2000"
            data-aos-once="true"
            data-aos-delay="1000"
            key={item.id}
          >
            <p>{item.en}</p>
            <p className="pt-2 dark:text-[#f06837] text-[#ee5a24]">
              -{item.author}-
            </p>
          </div>
        );
      })}
    </div>
  );
};
export default About;
